  ('judicial-57112235-moex-00287', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '關於受刑人不服假釋相關處分之救濟途徑種類，下列何者正確？', '["申訴", "給付訴訟", "確認訴訟", "訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00288', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["受刑人寄發及收受之書信，監獄人員不得開拆或以其他適當方式檢查有無夾藏違禁物品", "受刑人有妨害監獄秩序或安全之行為，尚在調查中者，監獄人員不得閱讀其書信內容", "有事實而合理懷疑受刑人有脫逃之虞者，監獄人員得閱讀其書信內容", "矯正機關收容人間互通之書信者，監獄人員不得閱讀其書信內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00289', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["受刑人有妨害監獄秩序或安全之行為時，監獄得停止其接受送入飲食三日至十四日", "受刑人有妨害監獄秩序或安全之行為時，監獄得視其情節，停止其使用自費購買之非日常生活必需 品七日至二十一日", "受刑人有妨害監獄秩序或安全之行為時，情節重大者，監獄得將其移入違規舍，期限為十四日以上， 三十日以下", "監獄非依監獄行刑法或其他法律規定，對於受刑人不得加以懲罰，同一事件不得重複懲罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00290', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法第83條，有關獎勵之規定，下列敘述何者錯誤？', '["舉發受刑人圖謀脫逃、暴行或將為脫逃、暴行者，監獄得予以獎勵", "無優良行為，監獄亦可考量得予以獎勵", "救護人命或捕獲脫逃者，監獄得予以獎勵", "於天災、事變或傳染病流行時，充任應急事務有勞績者，監獄得予以獎勵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00291', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["監獄對受刑人處分或管理措施之執行，因提起陳情或申訴而停止", "監獄對於受刑人，不得因陳情、申訴或訴訟救濟之提出，而施以歧視待遇或藉故懲罰", "受刑人向監獄、視察小組或其他視察人員提出陳情者，必須以書面為之", "監獄對於受刑人之陳情或提供意見，僅限於書面提出者，應為適當之處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00292', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["受刑人某甲，於A監獄接受有期徒刑之執行，不服監獄所為影響其個人權益之處分或管理措施者， 依法得以書面或言詞向監獄提起申訴", "受刑人某乙，於B監獄接受有期徒刑之執行，因監獄對其依本法請求之事件，拒絕其請求或於二個 月內不依其請求作成決定，認為其權利或法律上利益受損害，依法得以書面或言詞向監獄提起申訴", "受刑人某丙，於C監獄接受有期徒刑之執行，因監獄行刑之公法上原因發生之財產給付爭議，依法 得以書面或言詞向監獄提起申訴", "監獄認為受刑人之申訴有理由者，應立即召開申訴委員會，作成有利申訴人的決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00293', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關死刑執行之相關規定，下列敘述何者錯誤？', '["執行死刑，用槍決、藥劑注射或其他符合人道之適當方式為之", "執行槍決時，應由法醫師先對受刑人以施打或其他適當方式使用麻醉劑再執行", "執行槍決時，得對受刑人使用頭罩，使其面向行刑人，射擊部位定為心部並於其背後定其目標", "執行槍決時，行刑人與受刑人距離，不得逾2公尺，執行逾20分鐘後，由蒞場檢察官會同法醫師 立即覆驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00294', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者屬刑法第17條規定的加重結果犯？', '["警察追捕不接受酒駕臨檢的駕駛人，卻導致警車自撞分隔島，員警受傷", "小偷偷走被害人背包，背包中除了錢財外，尚有氣喘藥，後被害人因氣喘發作，藥物被小偷偷走未能及 時服藥而死亡", "駕駛因粗心闖紅燈，雖及時煞車未撞到行人，行人卻因驚嚇而心肌梗塞死亡", "原想給情敵一個教訓，卻在毆打情敵時不小心打到要害而導致情敵傷重死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00295', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何種非基於正當目的之接合行為，不該當刑法上之性交？', '["以手指與他人肛門接合", "以雨傘插入他人性器", "以酒瓶插入他人口腔", "以口腔與他人性器接合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00296', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者不適用刑法第2條第1項所揭示的從舊從輕原則？', '["有期徒刑", "褫奪公權", "罰金", "沒收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
